#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Node{
    int sum;
    Node *son[26];
}*root;

void clear(Node *p){
    p->sum=0;
    for(int i=0;i<26;i++)
        p->son[i]=NULL;
}

int n,m;
char s[N];

int main(){
    root=new Node;
    clear(root);
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%s",s+1);
        int len=strlen(s+1);
        Node *p=root;
        for(int j=1;j<=len;j++){
            if(p->son[s[j]-'a']==NULL){
                Node *q=new Node;
                clear(q);
                p->son[s[j]-'a']=q;
            }
            p=p->son[s[j]-'a'];
        }
        p->sum++;
    }
    for(int i=1;i<=m;i++){
        scanf("%s",s+1);
        int len=strlen(s+1),ans=0;
        Node *p=root;
        for(int j=1;j<=len;j++){
            if(p->son[s[j]-'a']==NULL)
                break;
            p=p->son[s[j]-'a'],ans+=p->sum;
        }
        printf("%d\n",ans);
    }
    return 0;
}
